changeSet.sql:
drop materialized view if exists sor.check_units; create materialized view if not exists sor.check_units as WITH actual_content AS ( SELECT history.content_id, history.content_version_id, content_info.irtz_type irtz_type FROM sor.content_history history JOIN sor.content_info content_info ON (history.content_id = content_info.content_id) and history.content_version_id = content_info.content_version_id and (history.end_dt = to_date('30000101'::text, 'YYYYMMDD'::text)) ), resources AS ( SELECT resources.id AS check_unit_id, actual_content.irtz_type, resources.content_id, resources.content_version_id, resources.value AS check_unit_value, types.dsc check_unit_type FROM (sor.content_resources resources JOIN sor.resource_type types ON ((resources.resource_type_id = types.id)) JOIN actual_content ON actual_content.content_id = resources.content_id and actual_content.content_version_id = resources.content_version_id JOIN sor.irtz_types_resourse_types irtz ON irtz.irtz_type = actual_content.irtz_type and irtz.resourse_type_id = resources.resource_type_id ) ) select * from resources;
alter materialized view sor.check_units owner to as_user;
create index if not exists check_unit_id_idx on sor.check_units (check_unit_id);

rollback.sql:
drop materialized view if exists sor.check_units; create materialized view if not exists sor.check_units as WITH actual_content AS ( SELECT history.content_id, history.content_version_id FROM sor.content_history history WHERE (history.end_dt = to_date('30000101'::text, 'YYYYMMDD'::text)) ), resources AS ( SELECT resources.id AS check_unit_id, resources.content_id, resources.content_version_id, resources.value AS check_unit_value, types.dsc AS check_unit_type FROM (sor.content_resources resources JOIN sor.resource_type types ON ((resources.resource_type_id = types.id)) JOIN actual_content on actual_content.content_id=resources.content_id and actual_content.content_version_id = resources.content_version_id ) ), actual_content_types AS ( SELECT actual_content.content_id, COALESCE(content_info.blocktype, 'url'::text) AS blocktype FROM (actual_content JOIN sor.content_info content_info ON ((actual_content.content_id = content_info.content_id) and actual_content.content_version_id = content_info.content_version_id)) ) SELECT resources.check_unit_id, actual_content_types.content_id, resources.check_unit_type, resources.check_unit_value FROM (actual_content_types JOIN resources ON (((actual_content_types.content_id = resources.content_id) AND (actual_content_types.blocktype = resources.check_unit_type))));
alter materialized view sor.check_units owner to as_user;
create index if not exists check_unit_id_idx on sor.check_units (check_unit_id);
